// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract AMM {
    uint256 public reserveA;
    uint256 public reserveB;
    uint256 public totalShares;
    mapping(address => uint256) public sharesOf;

    event LiquidityAdded(address indexed who, uint256 amountA, uint256 amountB, uint256 sharesMinted);
    event LiquidityRemoved(address indexed who, uint256 sharesBurned, uint256 amountA, uint256 amountB);

    function add(uint256 amountA, uint256 amountB) external returns (uint256 shares) {
        if (totalShares == 0) {
            shares = [[SLOT init_shares]];
        } else {
            uint256 sA = [[SLOT calc_a_shares]];
            uint256 sB = (amountB * totalShares) / reserveB;
            shares = [[SLOT min_pick]];
        }
        require(shares > 0, "zero shares");
        reserveA += amountA; reserveB += amountB;
        totalShares += shares;
        sharesOf[msg.sender] += shares;
        emit LiquidityAdded(msg.sender, amountA, amountB, shares);
    }

    function remove(uint256 shares) external returns (uint256 amountA, uint256 amountB) {
        amountA = (shares * reserveA) / totalShares;
        amountB = (shares * reserveB) / totalShares;
        sharesOf[msg.sender] -= shares;
        totalShares -= shares;
        reserveA -= amountA; reserveB -= amountB;
        emit LiquidityRemoved(msg.sender, shares, amountA, amountB);
    }

    function _sqrt(uint256 x) private pure returns (uint256 z) {
        if (x > 3) { z = x; uint256 y = x / 2 + 1; while (y < z) { z = y; y = (x / y + y) / 2; } }
        else if (x != 0) { z = 1; }
    }
}
